const SYM={S:"\u2660",H:"\u2665",D:"\u2666",C:"\u2663"};
const SUIT_NAME={S:"Spades",H:"Hearts",D:"Diamonds",C:"Clubs"};
const RED={H:true,D:true};
const MATCH_TARGET=52;
const DANGER_MARGIN=42;
const ROUND_IMG='data:image/jpeg;base64,';
let ws, state=null, me={seat:null,code:null,name:"",playerId:null,isSpectator:false};
let localSkipTaps={};
let pingTimer=null, reconnectTimer=null, intentionalClose=false, reconnecting=false, lastTrumpActive=false, trumpRevealCard=null, trumpRevealTimer=null, previousPhase=null;
try{ me.playerId=sessionStorage.getItem("br_pid")||null; me.code=sessionStorage.getItem("br_code")||null; me.name=sessionStorage.getItem("br_name")||""; me.isSpectator=sessionStorage.getItem("br_role")==="spectator"; }catch(e){}

function startPing(){
  clearInterval(pingTimer);
  pingTimer=setInterval(()=>{ if(ws && ws.readyState===1){ try{ ws.send(JSON.stringify({type:"ping"})); }catch(e){} } },20000);
}
function connect(then){
  const proto=location.protocol==="https:"?"wss":"ws";
  ws=new WebSocket(proto+"://"+location.host);
  ws.onopen=()=>{ reconnecting=false; startPing(); if(then) then(); };
  ws.onclose=()=>{
    clearInterval(pingTimer);
    if(intentionalClose) return;
    if(me.playerId && me.code){
      if(!reconnecting){ reconnecting=true; toast("Reconnecting\u2026"); }
      clearTimeout(reconnectTimer);
      reconnectTimer=setTimeout(()=>{ connect(()=>sendMsg({type:"rejoin",code:me.code,playerId:me.playerId})); }, 1500);
    }
  };
  ws.onerror=()=>{ try{ ws.close(); }catch(e){} };
  ws.onmessage=(ev)=>{
    const m=JSON.parse(ev.data);
    if(m.type==="pong") return;
    if(m.type==="joined"){
      me.seat=m.seat; me.code=m.code; me.playerId=m.playerId; me.isSpectator=!!m.isSpectator;
      try{sessionStorage.setItem("br_pid",m.playerId);sessionStorage.setItem("br_code",m.code);sessionStorage.setItem("br_role",me.isSpectator?"spectator":"player");}catch(e){}
    } else if(m.type==="state"){
      const wasActive = state ? state.trumpActive : false;
      const enteringHandover = (!state || state.phase !== "handover") && m.phase === "handover";
      if(enteringHandover){ localSkipTaps = {}; }
      const revealNow = !wasActive && m.trumpActive && m.trumpCard;
      previousPhase = state ? state.phase : null;
      state=m; me.seat=m.you; me.isSpectator=!!m.isSpectator;
      if(revealNow){
        trumpRevealCard=m.trumpCard;
        clearTimeout(trumpRevealTimer);
        trumpRevealTimer=setTimeout(()=>{ trumpRevealCard=null; render(false); }, 2000);
      }
      render(revealNow);
    } else if(m.type==="error") toast(m.message);
  };
}
function sendMsg(o){ if(ws && ws.readyState===1){ ws.send(JSON.stringify(o)); } }
const TEAM_OF=(seat)=>seat%2;
let tt; function toast(t){ const el=document.getElementById("toast"); el.textContent=t; el.classList.add("show"); clearTimeout(tt); tt=setTimeout(()=>el.classList.remove("show"),2800); }

function createRoom(){ const n=document.getElementById("nameInput").value.trim()||"Player"; me.name=n; me.isSpectator=false; try{sessionStorage.setItem("br_name",n);sessionStorage.setItem("br_role","player");}catch(e){} connect(()=>sendMsg({type:"create",name:n,playerId:me.playerId})); }
function joinRoom(){ const n=document.getElementById("nameInput").value.trim()||"Player"; const c=document.getElementById("codeInput").value.trim().toUpperCase(); if(c.length!==4)return toast("Enter the 4-letter code."); me.name=n; me.isSpectator=false; try{sessionStorage.setItem("br_name",n);sessionStorage.setItem("br_role","player");}catch(e){} connect(()=>sendMsg({type:"join",code:c,name:n,playerId:me.playerId})); }
function watchRoom(){ const n=document.getElementById("nameInput").value.trim()||"Spectator"; const c=document.getElementById("codeInput").value.trim().toUpperCase(); if(c.length!==4)return toast("Enter the 4-letter code."); me.name=n; me.isSpectator=true; try{sessionStorage.setItem("br_name",n);sessionStorage.setItem("br_role","spectator");}catch(e){} connect(()=>sendMsg({type:"spectate",code:c,name:n,playerId:me.playerId})); }
function createBotRoom(){ const n=document.getElementById("nameInput").value.trim()||"Player"; me.name=n; me.isSpectator=false; try{sessionStorage.setItem("br_name",n);sessionStorage.setItem("br_role","player");}catch(e){} connect(()=>sendMsg({type:"createBots",name:n,playerId:me.playerId})); }
function addBot(){ sendMsg({type:"addBot"}); }
function fillBots(){ sendMsg({type:"fillBots"}); }
function startGame(){ sendMsg({type:"start"}); }
function bid(a){ sendMsg({type:"bid",amount:a}); }
function pickTrump(cardId){ sendMsg({type:"pickTrump",cardId}); }
function playCard(id){ sendMsg({type:"play",cardId:id}); }
function nextHand(){ sendMsg({type:"nextHand"}); }
function skipMe(){ if(!state || state.phase!=="handover" || me.seat==null) return; if(state.skipsDone && state.skipsDone[me.seat]) return; const n=Math.min(13,(localSkipTaps[me.seat]||0)+1); localSkipTaps[me.seat]=n; if(n>=13){ sendMsg({type:"skip"}); } render(false); }
function newMatch(){ if(confirm("Reset this match and return everyone to the lobby?")) sendMsg({type:"newMatch"}); }

if(me.playerId&&me.code){ connect(()=>sendMsg({type:"rejoin",code:me.code,playerId:me.playerId})); }

function render(flashReveal=false){
  const wrap=document.getElementById("wrap");
  if(!state){ landing(wrap); return; }
  document.getElementById("scorebar").style.visibility = state.phase==="lobby"?"hidden":"visible";
  if(state.phase!=="lobby") updateScorebar();
  if(state.phase==="lobby") lobby(wrap); else tableView(wrap, flashReveal);
}
function updateScorebar(){
  const scorebar=document.getElementById("scorebar");
  const overallMargin=Math.abs((state.scores[0]||0)-(state.scores[1]||0));
  if(scorebar) scorebar.classList.toggle("danger", overallMargin>=DANGER_MARGIN);
  if(state.isSpectator || me.seat==null){
    document.getElementById("lab0").textContent="Team 1";
    document.getElementById("lab1").textContent="Team 2";
    document.getElementById("s0").textContent=state.scores[0]||0;
    document.getElementById("s1").textContent=state.scores[1]||0;
    return;
  }
  const myTeam=TEAM_OF(me.seat), opp=1-myTeam;
  const margin=(state.scores[myTeam]||0)-(state.scores[opp]||0);
  document.getElementById("lab0").textContent="Net · you";
  document.getElementById("lab1").textContent="Net · opp";
  document.getElementById("s0").textContent=margin>0?margin:0;
  document.getElementById("s1").textContent=margin<0?-margin:0;
}
function landing(wrap){
  wrap.innerHTML=`<div class="lobby" style="justify-content:flex-start;padding-top:38px;min-height:calc(100vh - 120px);">
    <div style="width:min(92vw,430px);border:1px solid rgba(201,162,63,.42);border-radius:24px;padding:22px 18px;background:radial-gradient(circle at 50% 20%,rgba(201,162,63,.13),rgba(0,0,0,.22) 42%,rgba(0,0,0,.40));box-shadow:0 18px 55px rgba(0,0,0,.48),inset 0 0 45px rgba(0,0,0,.25);">
      <div style="font-size:13px;letter-spacing:4px;text-transform:uppercase;color:#9bb3a8;margin-bottom:8px;">Hidden Trump · Online</div>
      <h2 style="font-size:34px;line-height:1.05;margin-bottom:10px;">Band Rang</h2>
      <p style="margin:0 auto 18px;max-width:330px;">Create a table, send the room code, or watch as spectator.</p>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:18px 0;">
        <div style="border:1px solid rgba(201,162,63,.25);border-radius:16px;padding:14px;background:rgba(0,0,0,.24);"><div style="font-size:24px;color:var(--gold);font-weight:700;">4</div><div style="font-size:11px;color:#c7d3cb;text-transform:uppercase;letter-spacing:1px;">players</div></div>
        <div style="border:1px solid rgba(201,162,63,.25);border-radius:16px;padding:14px;background:rgba(0,0,0,.24);"><div style="font-size:24px;color:var(--gold);font-weight:700;">1</div><div style="font-size:11px;color:#c7d3cb;text-transform:uppercase;letter-spacing:1px;">hidden trump</div></div>
      </div>
      <input id="nameInput" placeholder="Your name" maxlength="16" value="${esc(me.name)}" style="width:100%;max-width:280px;" />
      <div class="row" style="margin-top:14px;"><button class="btn" onclick="createRoom()" style="width:100%;max-width:280px;">Create a room</button></div><div class="row" style="margin-top:10px;"><button class="btn ghost" onclick="createBotRoom()" style="width:100%;max-width:280px;">Quick test · Play with 3 bots</button></div>
      <div class="or" style="margin:15px 0 8px;">— join or spectate —</div>
      <div class="row"><input id="codeInput" class="code" placeholder="CODE" maxlength="4" style="width:132px;" /><button class="btn ghost" onclick="joinRoom()">Join</button><button class="btn ghost" onclick="watchRoom()">Watch</button></div>
    </div>
  </div>`;
}
function lobby(wrap){
  const seated=state.players.filter(p=>p&&p.connected).length;
  const spectators=(state.spectators||[]).filter(p=>p&&p.connected);
  const seatCards=state.players.map((p,i)=>`<div style="border:1px solid ${p&&p.connected?'rgba(201,162,63,.65)':'rgba(155,179,168,.18)'};border-radius:16px;padding:12px;background:${p&&p.connected?'rgba(201,162,63,.10)':'rgba(0,0,0,.22)'};min-height:76px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:4px;">
    <div style="width:30px;height:30px;border-radius:50%;display:flex;align-items:center;justify-content:center;background:${p&&p.connected?'var(--gold)':'#2b3a35'};color:${p&&p.connected?'#1a1305':'#9bb3a8'};font-weight:800;">${p&&p.name?esc(p.name[0].toUpperCase()):i+1}</div>
    <div style="font-size:12px;color:#dce7e0;">Seat ${i+1}${i===me.seat?' (you)':''}</div>
    <div style="font-size:12px;color:${p?'var(--gold)':'#6c8479'};font-style:italic;">${p?esc(p.name):'empty'}${p&&p.bot?' · BOT':''}</div>
  </div>`).join("");
  wrap.innerHTML=`<div class="lobby" style="justify-content:flex-start;padding-top:28px;min-height:calc(100vh - 120px);">
    <div style="width:min(94vw,460px);border:1px solid rgba(201,162,63,.42);border-radius:24px;padding:20px;background:radial-gradient(ellipse at 50% 35%,rgba(15,93,74,.36),rgba(0,0,0,.28) 60%,rgba(0,0,0,.45));box-shadow:0 18px 55px rgba(0,0,0,.48),inset 0 0 60px rgba(0,0,0,.25);">
      <div style="font-size:14px;letter-spacing:3px;text-transform:uppercase;color:#9bb3a8;">Room code</div>
      <div class="codebig" style="font-size:54px;letter-spacing:12px;margin:6px 0 12px;">${state.code}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:16px 0;">${seatCards}</div>
      <p class="hint" style="max-width:360px;margin:12px auto;">Teams: seats 1 & 3 vs 2 & 4. Add bots to fill empty seats, or share this code for humans.</p>
      ${spectators.length?`<p class="hint">Watching: ${spectators.map(s=>esc(s.name)).join(", ")}</p>`:""}
      ${seated<4?`<div class="row" style="margin-top:10px;"><button class="btn ghost" onclick="addBot()">Add bot</button><button class="btn ghost" onclick="fillBots()">Fill with bots</button></div>`:""}
      <button class="btn" onclick="startGame()" ${seated===4?'':'disabled'} style="width:100%;max-width:280px;margin-top:10px;">${seated===4?'Start the game':`Waiting (${seated}/4)`}</button>
    </div>
  </div>`;
}
function pos(seat){ if(state && state.isSpectator) return ["bottom","left","top","right"][seat]; return ["bottom","left","top","right"][(seat-me.seat+4)%4]; }
function teamName(t){ if(state && state.isSpectator) return t===0?"Team 1":"Team 2"; return t===TEAM_OF(me.seat)?"your team":"opponents"; }
function cardText(c){ return c ? `${c.rank}${SYM[c.suit]}` : ""; }
function trumpBadgeHtml(){
  if(state.trumpActive && state.trumpCard){
    return `<span class="l">Trump</span><span class="sym ${RED[state.trumpCard.suit]?'red':'black'}">${cardText(state.trumpCard)}</span>`;
  }
  if(state.trumpActive && state.trump){
    return `<span class="l">Trump</span><span class="sym ${RED[state.trump]?'red':'black'}">${SYM[state.trump]}</span>`;
  }
  return `<span class="l">Trump</span><span class="hid">hidden</span>`;
}

function tableView(wrap, flashReveal){
  const playByPos={}; const src = state.trick.length?state.trick:(state.lastTrick?state.lastTrick.trick:[]);
  src.forEach(pl=>playByPos[pos(pl.seat)]=pl);
  const partnerSeat=state.isSpectator ? null : (me.seat+2)%4;
  const cardsRemaining=state.handCounts.reduce((a,b)=>a+b,0);
  const completed=Math.floor((52-cardsRemaining-state.trick.length)/4);
  const roundNum = state.phase==="playing" ? Math.min(13,completed+1) : null;
  const bidTeam = state.highBid ? (state.highBid.seat%2) : null;
  const myTeam=state.isSpectator ? 0 : TEAM_OF(me.seat), oppTeam=1-myTeam;
  const netMargin=(state.scores[myTeam]||0)-(state.scores[oppTeam]||0);
  const overallMargin=(state.scores[0]||0)-(state.scores[1]||0);
  const dangerMargin=Math.abs(overallMargin);
  const dangerTeam=overallMargin>=0?0:1;
  const showMatchDanger=dangerMargin>=DANGER_MARGIN && !state.khoti;

  function seatBox(p){
    let seat=null; for(let s=0;s<4;s++) if(pos(s)===p) seat=s;
    if(seat===null || (p==="bottom" && !state.isSpectator)) return "";
    const pl=state.players[seat];
    const active=(state.phase==="playing"&&state.turn===seat)||(state.phase==="bidding"&&state.bidTurn===seat)||(state.phase==="pickTrump"&&state.trumpHolder===seat);
    const nm=pl?esc(pl.name):"empty";
    const isP=seat===partnerSeat;
    const isHolder=state.trumpHolder===seat;
    const isBot=pl&&pl.bot;
    const bidShown = state.phase==="bidding"&&state.bids[seat]!=null ? (state.bids[seat]==="pass"?"pass":"bid "+state.bids[seat]) : "";
    return `<div class="seat ${p} ${active?'active':''} ${pl&&!pl.connected?'offline':''}">
      <div class="avatar">${nm[0]?nm[0].toUpperCase():'?'}</div>
      <div class="seatname">${nm}${isBot?' <span class="tag">BOT</span>':''}${isP?' <span class="tag">partner</span>':''}${isHolder?' <span class="tag">\u2756</span>':''}</div>
      ${bidShown?`<div class="tag">${bidShown}</div>`:''}
      <div class="seatname" style="font-size:10px;color:#9bb3a8">${state.handCounts[seat]} cards</div></div>`;
  }
  function playedHtml(p){
    const pl=playByPos[p]; if(!pl)return "";
    if(pl.faceDown || !pl.card) return `<div class="played ${p} back"><span>hidden</span></div>`;
    const c=pl.card; const isT=state.trumpActive&&c.suit===state.trump; const col=RED[c.suit]?"red":"black";
    return `<div class="played ${p} ${col}"><span class="c">${c.rank}</span><span class="p">${SYM[c.suit]}</span>${pl.zeroAce?'<span class="tdot">0</span>':(isT?'<span class="tdot"></span>':'')}</div>`;
  }

  const myTurn=!state.isSpectator && state.turn===me.seat;
  const portraitHand=window.matchMedia("(max-width: 520px) and (orientation: portrait)").matches && !state.isSpectator && state.hand.length>0;
  function handCardHtml(c,i,noOverlap=false){
    const margin=noOverlap||i===0?0:-22;
    const locked=!state.trumpActive && state.trumpCardId===c.id;
    if(locked){
      const col=RED[c.suit]?"red":"black";
      return `<button class="card locked ${col}" style="margin-left:${margin}px;z-index:${i}" disabled title="Your selected trump — locked until revealed"><span class="c">${c.rank}</span><span class="p">${SYM[c.suit]}</span><span class="small">locked trump</span></button>`;
    }
    const playable=state.phase==="playing"&&myTurn&&state.legal.includes(c.id);
    const dim=state.phase==="playing"&&myTurn&&!state.legal.includes(c.id);
    const col=RED[c.suit]?"red":"black";
    return `<button class="card ${col} ${playable?'playable':''} ${dim?'dim':''}" style="margin-left:${margin}px;z-index:${i}" ${playable?`onclick="playCard('${c.id}')"`:'disabled'}><span class="c">${c.rank}</span><span class="p">${SYM[c.suit]}</span></button>`;
  }
  let handHtml;
  if(portraitHand){
    const split=Math.ceil(state.hand.length/2);
    const first=state.hand.slice(0,split).map((c,i)=>handCardHtml(c,i,true)).join("");
    const second=state.hand.slice(split).map((c,i)=>handCardHtml(c,split+i,true)).join("");
    handHtml=`<div class="handrow">${first}</div><div class="handrow">${second}</div>`;
  }else{
    handHtml=state.hand.map((c,i)=>handCardHtml(c,i,false)).join("");
  }

  wrap.innerHTML=`<div class="table ${flashReveal?'flash':''} ${showMatchDanger?'near52':''} ${portraitHand?'portraitcards':''}">
    ${state.phase!=="handover"?`<button class="boardreset" onclick="newMatch()" title="Reset">Reset</button>`:""}
    ${showMatchDanger?`<div class="matchdanger"><span class="redlamp"></span><span class="dangertext">Team ${dangerTeam+1} is near 52</span><span class="dangernum">${dangerMargin}/52</span></div>`:""}
    <div class="trumpbadge">${trumpBadgeHtml()}</div>
    ${state.highBid?`<div class="bidbadge">Bid ${state.highBid.amount} \u00b7 ${teamName(bidTeam)}</div>`:''}
    <div class="infostack">
      <div class="roundb">${roundNum?`Round ${roundNum} / 13`:(state.phase==="bidding"?"Bidding":state.phase==="pickTrump"?"Choosing trump":"\u2014")}</div>
      <div class="pileb"><span class="n">${state.pile}</span><span class="l">in pile</span></div>
      <div class="scorecard">
        <div class="sline"><span class="nm">Your team</span><span class="nu" style="color:${myTeam===bidTeam?'#c9a23f':'#dce7e0'}">${state.tricksWon[myTeam]}${state.highBid&&bidTeam===myTeam?` / ${state.highBid.amount}`:''}</span></div>
        <div class="sline"><span class="nm">Opponents</span><span class="nu" style="color:${oppTeam===bidTeam?'#c9a23f':'#dce7e0'}">${state.tricksWon[oppTeam]}${state.highBid&&bidTeam===oppTeam?` / ${state.highBid.amount}`:''}</span></div>
      </div>
    </div>
    ${seatBox("top")}${seatBox("left")}${seatBox("right")}
    <div class="felt">${playedHtml("top")}${playedHtml("left")}${playedHtml("right")}${playedHtml("bottom")}<div class="feltmsg">${esc(state.message)}</div></div>
    ${biddingPanel()}
    ${trumpPanel()}
    <div class="handbottom"><div class="youtag">${state.isSpectator?"Watching as spectator":(myTurn&&state.phase==="playing"?"Your turn":(state.canBidNow?"Your bid":""))}</div><div class="fan ${portraitHand?'tworow':''}">${handHtml}</div></div>
    ${handoverOverlay(netMargin)}
    ${trumpRevealOverlay()}
  </div>`;
  if(flashReveal){ const t=wrap.querySelector(".table"); if(t) setTimeout(()=>t.classList.remove("flash"),1200); }
}

function biddingPanel(){
  if(!state.canBidNow) return "";
  const floor=state.bidFloor; const opts=[]; for(let b=floor;b<=13;b++)opts.push(b);
  const title = floor > 13 ? "No higher bid possible" : `Your bid (min ${floor})`;
  return `<div class="panel"><span class="t">${title}</span>
    ${opts.length ? `<div class="bidgrid">${opts.map(b=>`<button class="bidbtn" onclick="bid(${b})">${b}</button>`).join("")}</div>` : `<div class="hint">Only pass is available.</div>`}
    <button class="passbtn" onclick="bid('pass')">Pass</button></div>`;
}
function trumpPanel(){
  if(!state.isMyTrumpPick) return "";
  return `<div class="panel"><span class="t">Tap one card to hide as trump</span>
    <div class="pickcards">${state.hand.map(c=>`<button class="pickcard ${RED[c.suit]?'red':'black'}" onclick="pickTrump('${c.id}')"><span style="font-size:15px;font-weight:700;line-height:1">${c.rank}</span><span style="font-size:18px;line-height:1">${SYM[c.suit]}</span></button>`).join("")}</div></div>`;
}
function trumpRevealOverlay(){
  if(!trumpRevealCard) return "";
  const c=trumpRevealCard;
  const col=RED[c.suit]?"red":"black";
  return `<div class="trumpreveal"><div class="trumprevealbox"><div class="revealtext">Trump revealed</div><div class="bigcard ${col}"><span class="c">${c.rank}</span><span class="p">${SYM[c.suit]}</span></div></div></div>`;
}
function handoverOverlay(netMargin){
  if(state.phase!=="handover") return "";
  if(state.khoti){
    return `<div class="overlay"><div class="ocard" style="border:2px solid var(--gold)"><div class="t" style="font-size:20px;line-height:1.45">Losing team is a khoti Randi,</div><div class="sc" style="font-size:15px;color:var(--gold)">Winning team gets 20% discount with Nagma</div><div class="sc">Won by a margin of ${state.khoti.margin}.</div></div></div>`;
  }
  const loserTeam = state.loserTeam;
  const loserSeats = loserTeam==null ? [] : [0,1,2,3].filter(s=>TEAM_OF(s)===loserTeam);
  const allSkipped = loserSeats.length ? loserSeats.every(s=>state.skipsDone && state.skipsDone[s]) : true;
  const lossTitle = loserTeam==null ? "Hand finished." : `Team ${loserTeam+1} lost.`;
  const slots = loserSeats.length ? loserSeats.map(s=>skipBox(s)).join("") : "";
  return `<div class="overlay handover"><div class="lossstage" style="background-image:linear-gradient(rgba(4,7,6,.22),rgba(4,7,6,.42)),url('${ROUND_IMG}')">
    <div class="losstop"><div class="losstitle">${lossTitle}</div><div class="losssub">${allSkipped?"Done.":"Losing team must press TKMKBSDA to continue…"}</div></div>
    <div class="lossbuttons">${slots}</div>
    <div class="lossactions"><button class="btn" onclick="nextHand()" ${allSkipped?"":"disabled"}>${allSkipped?"Deal next hand":"Waiting for TKMKBSDA"}</button></div>
  </div></div>`;
}
function skipBox(seat){
  const p=state.players[seat];
  const name=esc(p?p.name:"Seat "+(seat+1));
  const done=state.skipsDone && state.skipsDone[seat];
  const mine=!state.isSpectator && seat===me.seat;
  const taps=localSkipTaps[seat]||0;
  const dx=((taps*37)%70)-35, dy=((taps*29)%48)-24;
  if(done) return `<div class="lossslot"><button class="btn lossbtn done" disabled>✓ TKMKBSDA</button><div class="lossname">${name}</div></div>`;
  if(mine) return `<div class="lossslot"><button class="btn lossbtn" style="transform:translate(${dx}px,${dy}px)" onclick="skipMe()">TKMKBSDA</button><div class="lossname">${name}</div><div class="losstaps">${Math.max(0,13-taps)} taps left</div></div>`;
  return `<div class="lossslot"><button class="btn lossbtn" disabled>TKMKBSDA</button><div class="lossname">${name}</div><div class="losstaps">waiting</div></div>`;
}
function esc(s){ return String(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
render();
